/**
 * Builds deterministic pseudo-random values for generated records.
 */
function seededNumber(index, modulo, seed) {
    return Math.abs((index * 9301 + seed * 49297 + 233280) % modulo);
}

/**
 * Produces stable date strings for generated records.
 */
function buildDate(index) {
    const month = String((index % 12) + 1).padStart(2, '0');
    const day = String((index % 28) + 1).padStart(2, '0');
    return `2026-${month}-${day}`;
}

/**
 * Clones a JSON-safe object graph.
 */
function clone(value) {
    return JSON.parse(JSON.stringify(value));
}

/**
 * Repeats and transforms a base dataset up to target count.
 */
function expandRecords(source, targetCount, transform) {
    if (targetCount <= source.length) {
        return clone(source);
    }

    const output = new Array(targetCount);
    for (let index = 0; index < targetCount; index += 1) {
        output[index] = transform(source[index % source.length], index);
    }

    return output;
}

/**
 * Converts likelihood and impact to risk level.
 */
function scoreToRiskLevel(score) {
    if (score >= 15) {
        return 'critical';
    }
    if (score >= 10) {
        return 'high';
    }
    if (score >= 5) {
        return 'medium';
    }
    return 'low';
}

/**
 * Returns target count per domain based on selected preset and safety cap.
 */
function resolveTargetCount(baseCount, preset, maxRecordsPerDomain) {
    const requested = scalePresetRecordsPerDomain[preset] ?? 0;
    if (requested === 0) {
        return baseCount;
    }

    const capped = Math.min(requested, maxRecordsPerDomain);
    return Math.max(baseCount, capped);
}

function buildRisks(targetCount, seed) {
    return expandRecords(BASE_DATA.risks, targetCount, (template, index) => {
        const likelihood = (seededNumber(index, 5, seed) % 5) + 1;
        const impact = (seededNumber(index + 7, 5, seed) % 5) + 1;
        const riskScore = likelihood * impact;
        return {
            ...template,
            id: buildId(DOMAIN_ID_PREFIX.risks, index),
            title: `${template.title} #${index + 1}`,
            likelihood,
            impact,
            riskScore,
            riskLevel: scoreToRiskLevel(riskScore),
            status: RISK_STATUSES[seededNumber(index, RISK_STATUSES.length, seed)],
            dueDate: buildDate(index + 30),
            createdAt: buildDate(index),
        };
    });
}

function buildFrameworks(targetCount, seed) {
    return expandRecords(BASE_DATA.frameworks, targetCount, (template, index) => {
        const totalControls = (seededNumber(index, 140, seed) % 140) + 30;
        const nonCompliantControls = seededNumber(index + 2, Math.max(2, Math.floor(totalControls * 0.2)), seed);
        const inProgressControls = seededNumber(index + 3, Math.max(2, Math.floor(totalControls * 0.15)), seed);
        const compliantControls = Math.max(0, totalControls - nonCompliantControls - inProgressControls);
        const score = Math.round((compliantControls / totalControls) * 100);

        return {
            ...template,
            id: buildId(DOMAIN_ID_PREFIX.frameworks, index),
            name: `${template.name} ${index + 1}`,
            totalControls,
            compliantControls,
            nonCompliantControls,
            inProgressControls,
            score,
        };
    });
}

function buildControls(targetCount, frameworksCount, seed) {
    return expandRecords(BASE_DATA.controls, targetCount, (template, index) => ({
        ...template,
        id: buildId(DOMAIN_ID_PREFIX.controls, index),
        frameworkId: buildId(DOMAIN_ID_PREFIX.frameworks, index % Math.max(1, frameworksCount)),
        controlId: `CC${(index % 9) + 1}.${(index % 8) + 1}`,
        title: `${template.title} #${index + 1}`,
        status: CONTROL_STATUSES[seededNumber(index, CONTROL_STATUSES.length, seed)],
        evidenceCount: (seededNumber(index, 7, seed) % 6) + 1,
        lastAssessedDate: buildDate(index + 11),
        createdAt: buildDate(index + 2),
    }));
}

