/**
 * Generates deterministic dummy data for all domains.
 */
export function generateDataset({ preset = 'small', seed = 42, maxRecordsPerDomain = 100_000, domains = ALL_DOMAINS } = {}) {
    const effectivePreset = Object.prototype.hasOwnProperty.call(scalePresetRecordsPerDomain, preset)
        ? preset
        : 'small';

    const requestedPerDomain = scalePresetRecordsPerDomain[effectivePreset] ?? 0;
    const appliedPerDomain = requestedPerDomain === 0
        ? 0
        : Math.min(requestedPerDomain, maxRecordsPerDomain);

    const frameworkTarget = resolveTargetCount(BASE_DATA.frameworks.length, effectivePreset, maxRecordsPerDomain);
    const auditTarget = resolveTargetCount(BASE_DATA.audits.length, effectivePreset, maxRecordsPerDomain);

    const fullDataset = {
        risks: buildRisks(resolveTargetCount(BASE_DATA.risks.length, effectivePreset, maxRecordsPerDomain), seed),
        frameworks: buildFrameworks(frameworkTarget, seed),
        controls: buildControls(resolveTargetCount(BASE_DATA.controls.length, effectivePreset, maxRecordsPerDomain), frameworkTarget, seed),
        audits: buildAudits(auditTarget, seed),
        findings: buildFindings(resolveTargetCount(BASE_DATA.findings.length, effectivePreset, maxRecordsPerDomain), auditTarget, seed),
        policies: buildPolicies(resolveTargetCount(BASE_DATA.policies.length, effectivePreset, maxRecordsPerDomain), seed),
        incidents: buildIncidents(resolveTargetCount(BASE_DATA.incidents.length, effectivePreset, maxRecordsPerDomain), seed),
        vendors: buildVendors(resolveTargetCount(BASE_DATA.vendors.length, effectivePreset, maxRecordsPerDomain), seed),
        partners: buildPartners(resolveTargetCount(BASE_DATA.partners.length, effectivePreset, maxRecordsPerDomain), seed),
    };

    const selectedDomains = domains.filter((domain) => ALL_DOMAINS.includes(domain));
    const dataset = {};
    for (const domain of selectedDomains) {
        dataset[domain] = fullDataset[domain];
    }

    return {
        dataset,
        meta: {
            preset: effectivePreset,
            seed,
            requestedPerDomain,
            appliedPerDomain,
            capped: requestedPerDomain > 0 && requestedPerDomain > maxRecordsPerDomain,
            maxRecordsPerDomain,
            domains: selectedDomains,
        },
    };
}
